module top_module(
          input clk, clear,
          input [7:0] cct_input,
          output reg [7:0] cct_output
			 );reg [7:0] obf_goofy_counter;

always @ (posedge clk)
if (clear == 1'b1) obf_goofy_counter = 8'b10000001;
else if (obf_goofy_counter == 8'b10000001) obf_goofy_counter = 8'b01000010;
else if (obf_goofy_counter == 8'b01000010) obf_goofy_counter = 8'b00100100;
else if (obf_goofy_counter == 8'b00100100) obf_goofy_counter = 8'b00011000;
else if (obf_goofy_counter == 8'b00011000) obf_goofy_counter = 8'b10000001;
else obf_goofy_counter = 8'b10000001;

always @ *
cct_output = obf_goofy_counter;

endmodule
